SELECT DISTINCT ?title WHERE {
  ?person wdt:P39 ?office.
  ?office wdt:P31/wdt:P279* wd:Q6550102.
  ?office rdfs:label ?title.
  FILTER(LANG(?title) = "en").
  FILTER(CONTAINS(STR(?title), "President")).
  FILTER NOT EXISTS { ?person wdt:P582 ?end }
}

